            throw new IllegalArgumentException("Date range must be in format 'startDate,endDate'");
        }

        String startDate = dateParts[0].trim();
        String endDate = dateParts[1].trim();

        // Validate date format (basic validation)
        if (!isValidDateFormat(startDate) || !isValidDateFormat(endDate)) {
            throw new IllegalArgumentException("Invalid date format. Expected format: YYYY-MM-DD");
        }

        // Call mapper to get results
        return salesMapper.getSalesByGroup(groupByField, startDate, endDate);
    }

    /**
     * Basic date format validation
     * 
     * @param date date string to validate
     * @return true if date matches YYYY-MM-DD format
     */
    private boolean isValidDateFormat(String date) {
        if (date == null || date.length() != 10) {
            return false;
        }

        // Check format YYYY-MM-DD
        if (date.charAt(4) != '-' || date.charAt(7) != '-') {
            return false;
        }

        try {
            // Try to parse year, month, day
            int year = Integer.parseInt(date.substring(0, 4));
            int month = Integer.parseInt(date.substring(5, 7));
            int day = Integer.parseInt(date.substring(8, 10));

            // Basic range validation
            return year >= 1900 && year <= 2100 && 
                   month >= 1 && month <= 12 && 
                   day >= 1 && day <= 31;
        } catch (NumberFormatException e) {
            return false;
        }
    }
}
